INSERT INTO public.photos VALUES (21699, 'Seguros la Catalana 1930', 'Juan Mora. 1930 Imagen de la reciente sede de "La Sociedad Catalana de Seguros contra incendios" de la plaza de la Constituciâ”œâ”‚n, esquina con el paseo de la Independencia, diseâ”œâ–’ada en 1928 en el clasicista y eclâ”œÂ®ctico lenguaje de carâ”œÃ­cter monumental que caracteriza a los edificios de entidades bancarias levantados durante los aâ”œâ–’os 20-30. En su diseâ”œâ–’o ya se ha tenido en cuenta introducir porches con arcos de medio punto. Fuente visual: "Aragâ”œâ”‚n : revista grâ”œÃ­fica de cultura aragonesa" (Aâ”œâ–’o VI, Nâ”¬â•‘ 63, diciembre 1930).', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65161000, -0.88102900, '0101000020E6100000917BBABA6331ECBF8FDFDBF467D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15487574359.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15487574359.webp', 'https://www.flickr.com/photos/zaragozaantigua/15487574359/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21703, 'Calle de San Miguel 1931', 'Imagen capturada en la calle de San Miguel junto a la fachada de las instalaciones de la compaâ”œâ–’â”œÂ¡a Elâ”œÂ®ctricas Reunidas de Zaragoza SA sitas en el nâ”¬â•‘ 8 de esa calle. Este edificio fue diseâ”œâ–’ado por Fâ”œÂ®lix Navarro Pâ”œÂ®rez en 1880 para El Prado Aragonâ”œÂ®s, teatro que en 1882 fue redenominado Teatro Goya hasta su cierre y venta en 1893 a la empresa termoelâ”œÂ®ctrica Electra Peral Zaragozana, que desde 1904 era parte de Sociedades Elâ”œÂ®ctricas Reunidas, y desde 1910 de Elâ”œÂ®ctricas Reunidas de Zaragoza. En la imagen aparece en toda su plenitud la fachada principal del original teatro, esquinero entre la calle de San Miguel y la calle de Isaac Peral, asâ”œÂ¡ denominada por la impronta de la elâ”œÂ®ctrica factorâ”œÂ¡a. Este edificio perdurâ”œâ”‚, con leves reformas, hasta su derribo integral en 1958 para construir sobre su solar una nueva y moderna sede de la empresa elâ”œÂ®ctrica. Al fondo, en la otra esquina, vista parcial del Teatro Circo. Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65101600, -0.88073900, '0101000020E6100000CFF9298E032FECBF1C96067E54D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15713611427.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15713611427.webp', 'https://www.flickr.com/photos/zaragozaantigua/15713611427/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
