INSERT INTO public.photos VALUES (21795, 'Pl. de Espaâ”œâ–’a 1938', 'Imagen capturada por un miembro de la "Legiâ”œâ”‚n Condor", desde el paseo de la Independencia, de la nueva plaza de Espaâ”œâ–’a, antes denominada "de la Constituciâ”œâ”‚n", cuando la habâ”œÂ¡a. En primer plano, una pancarta enfatiza uno de los significados que la fecha del "18 de julio" (de 1936) tenâ”œÂ¡a para quienes ese dâ”œÂ¡a se levantaron en armas contra la democracia. Al fondo, la soleada fachada del Coso, con la entrada a la calle de los Mâ”œÃ­rtires.', 1938, 1938, 1938, 'Anos 30', 'CENTRO', 41.65170200, -0.88119200, '0101000020E61000000CE6AF90B932ECBF705E9CF86AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24805216961.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24805216961.webp', 'https://www.flickr.com/photos/zaragozaantigua/24805216961/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
