INSERT INTO public.photos VALUES (21868, 'Calle de San Miguel 1933', 'Imagen capturada en la terraza del moderno Teatro-Cine Goya poco antes del inicio de una de las vespertinas sesiones al aire libre organizadas para tratar de mitigar el severo estâ”œÂ¡o local. La proyecciâ”œâ”‚n, en este caso, serâ”œÂ¡a la gran producciâ”œâ”‚n norteamericana de la Metro-Goldwyn-Mayer &quot;Mata-Hari&quot; (1931), protagonizada por Greta Garbo y Ramâ”œâ”‚n Novarro. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.65116000, -0.88062100, '0101000020E6100000537765170C2EECBF4F3BFC3559D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36507496101.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36507496101.webp', 'https://www.flickr.com/photos/zaragozaantigua/36507496101/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21871, 'Pl. de la Constituciâ”œâ”‚n 1931', 'Imagen centrada en la fachada del Gran Hotel de Europa tras el cese de su tradicional actividad, ya cerrado y en modo espera de la piqueta que lo derribarâ”œÂ¡a poco despuâ”œÂ®s. Este emblemâ”œÃ­tico establecimiento iniciâ”œâ”‚ sus actividades hacia 1845 como Fonda de Europa, en terrenos del antiguo y gran hospital de Ntra. Sra. de Gracia. En el momento de capturar esta imagen el edificio del hotel estaba etiquetado como un caserâ”œâ”‚n cargado de historia e historias, mas era considerado arcaico, decadente, viejo, que desdecâ”œÂ¡a a los modernos edificios del centro de la ciudad. Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65179300, -0.88028300, '0101000020E61000004D310741472BECBF8061F9F36DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37683796132.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37683796132.webp', 'https://www.flickr.com/photos/zaragozaantigua/37683796132/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21962, 'Plaza Espaâ”œâ–’a 1944', 'Trabajos de apilamiento de nieve en la plaza de Espaâ”œâ–’a, para despejar el trâ”œÃ­nsito rodado, tras la intensa nevada del 24 y 25 de febrero. Segâ”œâ•‘n la prensa de la â”œÂ®poca, es una de la mayores nevadas que se recuerdan. En el centro, el monumento a los Mâ”œÃ­rtires de la Religiâ”œâ”‚n y de la Patria, ante la embocadura del Coso Alto. A su derecha y al fondo, la sede provincial de la Falange Espaâ”œâ–’ola Tradicionalista y de las JONS, en el nâ”¬â•‘ 33 del Coso recayente a la plaza. Fuente: Colecciâ”œâ”‚n particular.', 1944, 1944, 1944, 'Anos 40', 'CENTRO', 41.65213600, -0.88081000, '0101000020E61000001DACFF73982FECBFAA45443179D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20864992522.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20864992522.webp', 'https://www.flickr.com/photos/zaragozaantigua/20864992522/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
