INSERT INTO public.photos VALUES (25633, 'La Romareda 1957', 'Desde la altura de la Residencia Sanitaria Josâ”œÂ® Antonio, una despejada vista panorâ”œÃ­mica con un primer plano del nuevo Estadio Municipal de La Romareda, en el proyectado Polâ”œÂ¡gono Gran Vâ”œÂ¡a. Detrâ”œÃ­s e inmediata, la antigua carretera de Valencia, surtida de torres y campos de cultivo, y al fondo, agreste panorama hasta el entorno del Hospital Psiquiâ”œÃ­trico Nuestra Seâ”œâ–’ora del Pilar, que alcanza incluso hasta el Grupo de Viviendas "Arzobispo Domenech" en la Vâ”œÂ¡a Hispanidad. Fuente visual: AMZ', 1957, 1957, 1957, 'Anos 50', 'UNIVERSIDAD', 41.63655900, -0.90191300, '0101000020E6100000BCCADAA678DCECBFBB7CEBC37AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40118878123.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40118878123.webp', 'https://www.flickr.com/photos/zaragozaantigua/40118878123/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22430, 'Pl. de Espaâ”œâ–’a 1967', 'Unidad de la serie "300" de la tranviaria lâ”œÂ¡nea 11 "Parque", llegando a su terminal situada en la plaza de Espaâ”œâ–’a, donde procederâ”œÃ­ a dar la vuelta para recomenzar el trayecto hasta el antiguo parque de Buenavista. A finales de ese aâ”œâ–’o, esta lâ”œÂ¡nea serâ”œÂ¡a unificada con la 13, "San Josâ”œÂ®", conformando la nueva lâ”œÂ¡nea "Parque-San Josâ”œÂ®", que con el guarismo 11 supervivirâ”œÂ¡a prestando servicio pâ”œâ•‘blico hasta enero de 1976, en que fue ejecutada su clausura, siendo entonces la â”œâ•‘ltima en la ciudad de este antiguo y apreciado gâ”œÂ®nero de transporte urbano, en su versiâ”œâ”‚n clâ”œÃ­sica. Al fondo, a la derecha, recayente al paseo de la Independencia, la imponente mole de la moderna gran superficie comercial en vertical de la Sociedad Espaâ”œâ–’ola de Precios â”œÃœnicos, durante su â”œâ•‘ltima fase de construcciâ”œâ”‚n, antes de ser inaugurada ese mismo aâ”œâ–’o. Fuente: www.ebay.es/', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.65191800, -0.88069800, '0101000020E61000002AE27492AD2EECBF3DD68C0C72D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29106616025.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29106616025.webp', 'https://www.flickr.com/photos/zaragozaantigua/29106616025/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22502, 'Coso Medio c.1964', 'Imagen de la composiciâ”œâ”‚n tranviaria M+R 109 en servicio en la lâ”œÂ¡nea 17. Las Fuentes capturada en el arranque del Coso Medio y encaminada hacia la perifâ”œÂ®rica barriada que le daba nombre. Hacia el fondo y a la izquierda, guardia urbano regula el trâ”œÃ­fico en la plaza de Espaâ”œâ–’a. Tras el tranvâ”œÂ¡a, la achaflanada esquina del Banco Zaragozano que indica el principio de la calle de Don Jaime I.', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65186300, -0.87982800, '0101000020E6100000E25CC30C8D27ECBF793C2D3F70D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49903643998.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49903643998.webp', 'https://www.flickr.com/photos/zaragozaantigua/49903643998/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
