INSERT INTO public.photos VALUES (22573, 'Calle Don Jaime I, 1973', 'Câ”œÂ®sar Sâ”œÃ­nchez Vâ”œÃ­zquez. 1973. Imagen de la fachada del edificio del estudio de "Jarke", en la calle Don Jaime I, 2. En 1918, Câ”œÂ®sar Gracia Jarke se estableciâ”œâ”‚ como fotâ”œâ”‚grafo con el nombre de â”¬Â½Jarkeâ”¬â•—, (continuando luego su hijo Josâ”œÂ® Antonio) especializâ”œÃ­ndose en fotografâ”œÂ¡a industrial aunque, como buen imaginero, tocaba todos los palos. Fuente visual: www.facebook.com/groups/fotosantiguasdezaragoza/792846500...', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65202200, -0.87992900, '0101000020E6100000DAA9B9DC6028ECBFE222F77475D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15413073919.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15413073919.webp', 'https://www.flickr.com/photos/zaragozaantigua/15413073919/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22693, 'Pl. de Espaâ”œâ–’a 1970', 'Colorista imagen de la plaza de Espaâ”œâ–’a centrada en el paâ”œâ–’o de la fachada entre las calles de los Mâ”œÃ­rtires y Don Jaime I, cuando los remates edilicios estaban poblados de luminosos anuncios comerciales de neâ”œâ”‚n, de considerable efecto visual nocturno. El denso trâ”œÃ­fico rodado todavâ”œÂ¡a incluye elementos tranviarios. Esta captura fue realizada por la australiana Lindsay Bridge un luminoso dâ”œÂ¡a de junio de 1970, durante su paso por la ciudad. Fuente visual: www.flickr.com/photos/intervene/4159219218/in/album-72157...', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65200200, -0.88073900, '0101000020E6100000CFF9298E032FECBF9B7631CD74D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27314010316.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27314010316.webp', 'https://www.flickr.com/photos/zaragozaantigua/27314010316/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22694, 'Pl. de Espaâ”œâ–’a 1970', 'Entraâ”œâ–’able y colorista imagen parcial de la plaza de Espaâ”œâ–’a, junto al banco del â”œÂ¡dem, cuando todavâ”œÂ¡a era posible asistir al tranviario cruce de la lâ”œÂ¡nea 5 ("Venecia-Delicias"), en este caso la veterana composiciâ”œâ”‚n 59+87 en direcciâ”œâ”‚n hacia la plaza de Huesca, con la lâ”œÂ¡nea 11 ("Parque-San Josâ”œÂ®"), una novâ”œÂ¡sima unidad 300 en direcciâ”œâ”‚n a la calle de Suiza del barrio de San Josâ”œÂ®. Un aâ”œâ–’o despuâ”œÂ®s, la lâ”œÂ¡nea 5 fue desmantelada. La lâ”œÂ¡nea 11 fue la â”œâ•‘ltima del antiguo y provinciano tranvâ”œÂ¡a, clausurada a comienzos de 1976. Esta captura fue realizada por la australiana Lindsay Bridge un luminoso dâ”œÂ¡a de junio de 1970, durante su paso por la ciudad. Fuente visual: www.flickr.com/photos/intervene/1994932855/in/album-72157...', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65191300, -0.88037400, '0101000020E610000062F54718062CECBF2B6B9BE271D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27315484876.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27315484876.webp', 'https://www.flickr.com/photos/zaragozaantigua/27315484876/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22804, 'Coso Medio 1972', 'Antolâ”œâ”‚gica imagen centrada en el veterano paso de peatones habilitado en el arranque del tramo medio del Coso, entre la esquina de la plaza de Espaâ”œâ–’a inmediata al homâ”œâ”‚nimo Banco (a la izquierda y fuera de plano), y el inmueble de los nâ”œâ•‘meros 43-45 del Coso del fondo, en cuyos bajos comerciales destaca la Farmacia Râ”œÂ¡os. A la izquierda, ingreso al Tubo por la calle de los Mâ”œÃ­rtires. El firme mojado por la lluvia primaveral conserva el antiguo pavimento adoquinado, trufado de los modernos parches asfâ”œÃ­lticos, ademâ”œÃ­s del trazado de la tranviaria lâ”œÂ¡nea 11. Parque-San Josâ”œÂ®. Por este estratâ”œÂ®gico cruce, y cuando el semâ”œÃ­foro lo disponâ”œÂ¡a, circulaba el intenso trâ”œÃ­fico motorizado que desde la calle de Don Jaime I se encaminaba hacia las carreteras de Madrid y de Valencia.', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65204000, -0.88025800, '0101000020E6100000145B41D3122BECBF88D7F50B76D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48126008662.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48126008662.webp', 'https://www.flickr.com/photos/zaragozaantigua/48126008662/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
