INSERT INTO public.photos VALUES (22827, 'Calle de San Miguel 1970', 'Decembrina y nocturna escena capturada desde la calle de los Sitios y centrada en la achaflanada fachada de la sede social de la empresa Elâ”œÂ®ctricas Reunidas de Zaragoza que destaca decorada con iluminaciâ”œâ”‚n de temporada basada en elementos astrolâ”œâ”‚gicos y mitolâ”œâ”‚gicos varios. En un entorno de calles adoquinadas, la calle de San Miguel aparece asfaltada de forma pionera.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65094100, -0.88054700, '0101000020E6100000C0E8F2E6702DECBF1250E10852D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52838332327.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52838332327.webp', 'https://www.flickr.com/photos/zaragozaantigua/52838332327/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23062, 'Plaza de Espaâ”œâ–’a 1992', 'Imagen capturada en la plaza de Espaâ”œâ–’a y orientada hacia la fachada del Coso recayente a ella. En primer tâ”œÂ®rmino, la rotonda automovilâ”œÂ¡stica con el Monumento a los Mâ”œÃ­rtires de la Religiâ”œâ”‚n y la Patria en el centro. Al fondo y hasta la entrada a la calle de los Mâ”œÃ­rtires, inmuebles del Coso en trâ”œÃ­nsito hacia la rehabilitaciâ”œâ”‚n y/o derribo, destacando en el solar del ya desaparecido nâ”¬â•‘ 35 la efâ”œÂ¡mera exhibiciâ”œâ”‚n de dos pancartas reivindicativas, una advirtiendo de los riesgos de la central nuclear mâ”œÃ­s antigua de Espaâ”œâ–’a, y la otra una carta a los reyes magos pidiendo la libertad del insumiso Antonio Oriol.', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.65204000, -0.88104100, '0101000020E6100000A2EC2DE57C31ECBF88D7F50B76D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50509020197.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50509020197.webp', 'https://www.flickr.com/photos/zaragozaantigua/50509020197/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23130, 'Pl. de Espaâ”œâ–’a 2006', 'Foto: Pedro Etura. Vista de la plaza de Espaâ”œâ–’a, con el Coso Medio al fondo a la izquierda, y el paseo de la Independencia a la derecha. Tras el monumento a los Mâ”œÃ­rtires, el Banco de Espaâ”œâ–’a. Este diseâ”œâ–’o de rotonda automovilâ”œÂ¡stica, implantado en 1961 y modificado en 1976 y 2002, serâ”œÃ­ readaptado con motivo de las obras de la segunda fase de la lâ”œÂ¡nea 1 del tranvâ”œÂ¡a (2011-2013). Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'CENTRO', 41.65214900, -0.88100000, '0101000020E6100000FED478E92631ECBF3F8F519E79D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31610110310.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31610110310.webp', 'https://www.flickr.com/photos/zaragozaantigua/31610110310/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
