INSERT INTO public.photos VALUES (23204, 'Pl. de Espaâ”œâ–’a 2010', 'Foto: Vâ”œÂ¡ctor Lax. Una grâ”œâ•‘a coloca en la plaza de Espaâ”œâ–’a una maqueta a tamaâ”œâ–’o real de un fragmento de vagâ”œâ”‚n del futuro tranvâ”œÂ¡a de la ciudad, en abril de 2010. Se trataba de una promociâ”œâ”‚n para dar a conocer este nuevo servicio, que entrâ”œâ”‚ en funcionamiento un aâ”œâ–’o despuâ”œÂ®s. Fuente: Heraldo de Aragâ”œâ”‚n.', 2010, 2010, 2010, 'Siglo XXI', 'CENTRO', 41.65213300, -0.88089300, '0101000020E61000007DCF48844630ECBF39D2191879D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32670741704.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32670741704.webp', 'https://www.flickr.com/photos/zaragozaantigua/32670741704/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
