INSERT INTO public.photos VALUES (23275, 'Hospital Nuestra Seâ”œâ–’ora de Gracia 1808', '"Vista del costado de la Yglesia del Hospital General de Nuestra Seâ”œâ–’ora de Gracia", grabado de la serie "Ruinas de Zaragoza" de Juan Gâ”œÃ­lvez y Fernando Brambila, 1812-1813. Aspecto del interior de las instalaciones del Hospital, con la espadaâ”œâ–’a de la entrada a la iglesia al fondo a la izquierda, en una vista trasera del mismo edificio que aparece en el grabado "Vista de la calle del Coso" de la misma colecciâ”œâ”‚n (www.flickr.com/photos/zaragozaantigua/19083373031/). Fuente visual: www.bibliotecavirtualdeandalucia.es/', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.65179100, -0.88049400, '0101000020E61000000B60CAC0012DECBFE06932E36DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21085205636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21085205636.webp', 'https://www.flickr.com/photos/zaragozaantigua/21085205636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23276, 'Coso 1808', 'Versiâ”œâ”‚n de la "Vista de la calle del Coso" de Gâ”œÃ­lvez y Brambila. Muestra el espacio del Coso de Zaragoza que ocuparâ”œÃ­ despuâ”œÂ®s la plaza de San Fernando, actual plaza de Espaâ”œâ–’a, visto desde la confluencia con la actual calle de Don Jaime. A la izquierda, la iglesia del Hospital de Nuestra Seâ”œâ–’ora de Gracia o de Locos. A la derecha, con tres torretas, la entrada a la iglesia del convento de San Francisco, al que tambiâ”œÂ®n corresponde la torre alta de la izquierda. Aunque no se ve, entrambos edificios se halla el estrecho camino de Santa Engracia, hoy paseo de la Independencia. A la derecha, ruinas de la Cruz del Coso, tras las que continâ”œâ•‘a la calle, en la zona del palacio de Sâ”œÃ­stago. En primer plano, como principal variante del dibujo original, las Hermanas de la Caridad de Santa Ana trasladan a los enfermos del Hospital a la Casa de Misericordia. Su directora, la Madre Rafols, pasâ”œâ”‚ a ser legendaria heroâ”œÂ¡na de la contienda, y figura simbâ”œâ”‚lica de los reaccionarios locales, desde la llegada de la Segunda Repâ”œâ•‘blica y sobre todo a partir de la Guerra Civil. Hay quien asegura que los locos que lograron escapar por su propio pie del Hospital, huyeron hasta el monte de Torrero, donde una parte se lanzâ”œâ”‚ al Canal Imperial, pereciendo ahogados; y que los supervivientes, al ver a las monjas que corrâ”œÂ¡an tras ellos, las siguieron cual corderillos. Fuente visual: Postal editada por las Hermanas de la Caridad de Santa Ana de Zaragoza.', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.65213600, -0.88081000, '0101000020E61000001DACFF73982FECBFAA45443179D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30500435730.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30500435730.webp', 'https://www.flickr.com/photos/zaragozaantigua/30500435730/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23605, 'Plaza de Espaâ”œâ–’a 1952', 'AHPZ-Archivo Coyne, Manuel Coyne, 1952. Plaza de Espaâ”œâ–’a desde el Coso Medio.', 1952, 1952, 1952, 'Anos 50', 'CENTRO', 41.65195900, -0.87985500, '0101000020E6100000481B47ACC527ECBF9BAA7B6473D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14885938632.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14885938632.webp', 'https://www.flickr.com/photos/zaragozaantigua/14885938632/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23608, 'Coso Medio 1955', 'El coche de caballo era signo de ostentaciâ”œâ”‚n socioeconâ”œâ”‚mica, exclusiva seâ”œâ–’al de pertenencia al estamento, luego clase, dominante. Zaragoza tenâ”œÂ¡a su parque de coches a propulsiâ”œâ”‚n de sangre, y al principio era cosa de condes, marqueses, barones, y del arzobispo catâ”œâ”‚lico. En el XIX se les uniâ”œâ”‚ el Capitâ”œÃ­n General de la Regiâ”œâ”‚n Militar, el Gobernador Civil, y el presidente de la DPZ. El alcalde tenâ”œÂ¡a uno, alquilado, de un solo caballo (de 1923 es el primer automâ”œâ”‚vil municipal). Tambiâ”œÂ®n se lo agenciaron los miembros de la clase dirigente que, aun sin tâ”œÂ¡tulo nobiliario, tenâ”œÂ¡an excelente talonario. En los aâ”œâ–’os 60 del pasado siglo quedaban unos cinco coches de caballos traqueteando por la ciudad. En la imagen, coche de caballo aparcado al lado del Teatro Principal, en el Coso Medio. Detrâ”œÃ­s, junto a la embocadura a la calle de los Sitios, un trolebâ”œâ•‘s de la lâ”œÂ¡nea del Gâ”œÃ­llego. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65191100, -0.87980700, '0101000020E6100000045779026127ECBF8A73D4D171D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15180539329.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15180539329.webp', 'https://www.flickr.com/photos/zaragozaantigua/15180539329/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23609, 'Coso 1963', 'Foto Robert A. Hall, julio de 1963. Tramo del Coso Medio en las inmediaciones con la plaza de Espaâ”œâ–’a (al fondo). En el centro de la imagen, calle de Los Sitios. Fuente: Los tranvâ”œÂ¡as de Zaragoza, 1985.', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.65189400, -0.87982900, '0101000020E6100000F850A2258F27ECBFB43A394371D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15263088053.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15263088053.webp', 'https://www.flickr.com/photos/zaragozaantigua/15263088053/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23613, 'Coso Medio 1959', 'El Teatro Principal desde cierta altura, en una vista del Coso que alcanza hasta el colegio de los Escolapios, al fondo. El teatro presenta el aspecto exterior tras la reforma proyectada por Josâ”œÂ® Beltrâ”œÃ­n y Regino Borobio e inaugurada en 1940, aunque sin la decoraciâ”œâ”‚n escultâ”œâ”‚rica de la fachada, que finalmente se instalarâ”œÂ¡a a finales de los aâ”œâ–’os 60. En la acera solanera del Coso destacan los toldos de los comercios, y sobre el inmueble del nâ”¬â•‘ 1 de la plaza de Espaâ”œâ–’a y el Casino Mercantil los palomares que hacen de remate, ambos luego desaparecidos. Junto a los â”œÃ­rboles de la plaza de Espaâ”œâ–’a, un guardia urbano ordena el trâ”œÃ­fico de personas, tranvâ”œÂ¡as y demâ”œÃ­s vehâ”œÂ¡culos. Fuente: Instituto Amatller de Arte Hispâ”œÃ­nico (Arxiu Mas), convertida luego en postal por la editorial Garcâ”œÂ¡a Garrabella.', 1959, 1959, 1959, 'Anos 50', 'CENTRO', 41.65189400, -0.87982900, '0101000020E6100000F850A2258F27ECBFB43A394371D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15704941220.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15704941220.webp', 'https://www.flickr.com/photos/zaragozaantigua/15704941220/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23619, 'Calle Don Jaime I 1899', '"Rue de la Bourse", Renâ”œÂ® Ancely, 1899. Imagen de la entrada a la calle de Don Jaime I desde el Coso. En el original, esta calle aparece denominada "Rue de la Bourse", por conducir a la Lonja ("Bourse"). Al fondo, despunta la torre de la Seo. Sobre el firme los primitivos tendidos tranviarios por donde transitaban las lâ”œÂ¡neas del Arrabal (por la calle Don Jaime I), la de Circunvalaciâ”œâ”‚n (Coso), y la del Bajo Aragâ”œâ”‚n, hasta la Estaciâ”œâ”‚n de Cappa. El fresco, aun con sol de invierno, se combate mejor con capa. Fuente: www.georgesancely.com/', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.65202100, -0.88008800, '0101000020E6100000FA43334FAE29ECBF11A7936C75D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27306160341.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27306160341.webp', 'https://www.flickr.com/photos/zaragozaantigua/27306160341/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23622, 'Coso Medio 1954', 'Dos trolebuses (un BUT de 1 piso, y un VETRA) de la nueva lâ”œÂ¡nea del Gâ”œÃ­llego, aparcados en el Coso Medio durante su oficial puesta de largo, con la plaza de Espaâ”œâ–’a al fondo. La Terminal de lâ”œÂ¡nea se estableciâ”œâ”‚ aâ”œâ–’os despuâ”œÂ®s en la calle de la Verâ”œâ”‚nica. Fuente visual: HA', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.65182800, -0.87985200, '0101000020E6100000033FAA61BF27ECBFFD4E93196FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32514782406.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32514782406.webp', 'https://www.flickr.com/photos/zaragozaantigua/32514782406/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23623, 'Coso Medio 1954', 'En el Coso Medio, tramo comprendido entre las plazas de Espaâ”œâ–’a y de San Miguel, imagen en primer plano de dos trolebuses durante la inauguraciâ”œâ”‚n oficial del nuevo servicio de la lâ”œÂ¡nea Gâ”œÃ­llego que conectaba esta terminal, esquinera con la calle de Blancas, con la del puente del râ”œÂ¡o Gâ”œÃ­llego situado a la entrada al barrio de Santa Isabel. Los trolebuses estacionados han llegado desde la calle de Don Jaime I, cuyo entorno alrededor de la esquina del Banco Zaragozano muestra una bulliciosa actividad de viandantes y vehâ”œÂ¡culos. Fuente visual: AHPZ.', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.65182800, -0.87985200, '0101000020E6100000033FAA61BF27ECBFFD4E93196FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33477861516.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33477861516.webp', 'https://www.flickr.com/photos/zaragozaantigua/33477861516/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23625, 'Coso Medio c.1897', 'Imagen capturada en el tramo medio del Coso, donde un ceremonioso desfile de tropas de caballerâ”œÂ¡a queda enmarcado por el escâ”œÂ®nico telâ”œâ”‚n de fondo edilicio de los nâ”œâ•‘meros 55 al 65, esquinero con la calle del Teatro, e incluso la casa que fuera de Simâ”œâ”‚n Ignacio Tarazona, desde 1875 sucursal del Banco de Espaâ”œâ–’a en Zaragoza. La fachada del Teatro Principal, aâ”œâ•‘n sin marquesina, resultado de la reforma acometida con proyecto de Ricardo Magdalena. Fuente visual: cesbor.blogspot.com.es/', 1897, 1897, 1897, 'Siglo XIX', 'CENTRO', 41.65185700, -0.87969800, '0101000020E610000055698B6B7C26ECBF9755D80C70D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39715644304.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39715644304.webp', 'https://www.flickr.com/photos/zaragozaantigua/39715644304/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23628, 'Coso Medio 1963', 'Veraniega imagen capturada hace 56 aâ”œâ–’os en el arranque del tramo medio del Coso, y centrada en el trolebâ”œâ•‘s Pegaso nâ”¬â•‘ 34 de la lâ”œÂ¡nea Barrio Jesâ”œâ•‘s estacionado en la terminal sita originalmente en esta ubicaciâ”œâ”‚n, y aâ”œâ–’os despuâ”œÂ®s trasladada a la calle de la Verâ”œâ”‚nica. A la derecha circula un tranvâ”œÂ¡a de la serie 200, subserie de los "Rizados", en servicio en la lâ”œÂ¡nea 13. San Josâ”œÂ®, que unos aâ”œâ–’os despuâ”œÂ®s, junto con la lâ”œÂ¡nea 11. Parque, conformarâ”œÂ¡a la nueva lâ”œÂ¡nea 11. Parque-San Josâ”œÂ®, la â”œâ•‘ltima de la histâ”œâ”‚rica red de tranvâ”œÂ¡as en ser desmantelada en 1976. Tras ellos, el desemboque de la calle de Los Sitios en el Coso Medio, que luce el aspecto de los antiguos inmuebles del nâ”¬â•‘ 54 al nâ”¬â•‘ 62. Tiempo despuâ”œÂ®s, el nâ”¬â•‘ 54 serâ”œÂ¡a derribado e ingeniosamente adicionado al Banco de Espaâ”œâ–’a. Antes, los nâ”œâ•‘meros 56 y 62 serâ”œÂ¡an derribados para dar paso, con desigual resultado, a modernos, bien verticales y finos edificios de viviendas y oficinas comerciales. Al fondo y a la derecha se abre la plaza de Espaâ”œâ–’a.', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.65171100, -0.87983900, '0101000020E6100000DCD9571EA427ECBFC3B81B446BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48290434971.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48290434971.webp', 'https://www.flickr.com/photos/zaragozaantigua/48290434971/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23631, 'Coso Medio c.1859', 'Imagen desde cierta altura del tramo del Coso Medio que al fondo arranca en la plaza de la Constituciâ”œâ”‚n. A la izquierda e inmediata, manzana comprendida entre la calle de los Sitios y la plaza, donde destacaba el Gran Hotel Restaurante de Europa. Al fondo, la Fuente de la Princesa mâ”œÃ­s cerca del arranque del salâ”œâ”‚n de Santa Engracia. Entre el edificio de la Diputaciâ”œâ”‚n y el inmueble del nâ”¬â•‘ 1 de la plaza perdura un pequeâ”œâ–’o solar tapiado, recuerdo de un antiguo pasaje, que poco despuâ”œÂ®s se anexarâ”œÂ¡a como ampliaciâ”œâ”‚n de su vecino nâ”¬â•‘ 1. A la derecha, el principio de la calle de Don Jaime I. El aspecto aparentemente despoblado indica que se trata de una de las primeras fotografâ”œÂ¡as tiradas en esta zona de la ciudad, bastante antes de la instalaciâ”œâ”‚n de las primeras lâ”œÂ¡neas de tranvâ”œÂ¡as tirados por caballerâ”œÂ¡as.', 1859, 1859, 1859, 'Siglo XIX', 'CENTRO', 41.65195900, -0.88002200, '0101000020E61000001D56B8E52329ECBF9BAA7B6473D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50859368266.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50859368266.webp', 'https://www.flickr.com/photos/zaragozaantigua/50859368266/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23870, 'Pl. de Espaâ”œâ–’a 1954', 'Vista del paseo de la Independencia y la plaza de Espaâ”œâ–’a, con el Pilar al fondo. Fuente visual: Editorial Garcâ”œÂ¡a Garrabella, en www.todocoleccion.net/', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.65211300, -0.88109900, '0101000020E6100000C939B187F631ECBFF225547078D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30761465114.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30761465114.webp', 'https://www.flickr.com/photos/zaragozaantigua/30761465114/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
